def compute_score():
    # Acceptable changes: add one text box to slide 1, add hyperlink, no other slides added/removed/modified
    extraneous = False
    # Slides added/removed other than required
    if len(ppt_diff.added_slides) > 0:
        for slide in ppt_diff.added_slides:
            if slide.slide_number != 1:
                extraneous = True
    if len(ppt_diff.removed_slides) > 0:
        extraneous = True
    # Check for other text boxes added to other slides
    for before, after in ppt_diff.modified_slides:
        if after.slide_number != 1:
            if after.element_count != before.element_count:
                extraneous = True
    # Check for animations, transitions, hyperlinks added other than required
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        extraneous = True
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        extraneous = True
    if extraneous:
        return "Extraneous changes detected in PowerPoint beyond the required text box and hyperlink.", 0.0
    return "No extraneous changes detected.", 1.0
